  const mapRef = useRef<SVGSVGElement | null>(null);

  useEffect(() => {
    if (!mapRef.current) return;
    const svg = mapRef.current;

    // Clear old highlights
    svg.querySelectorAll('.highlighted-state').forEach(el => el.classList.remove('highlighted-state'));

    // Apply new highlights based on the prop
    highlightedCountries.forEach(countryCode => {
      const countryEl = svg.querySelector<SVGPathElement>(`#${countryCode}`);
      if (countryEl) {
        countryEl.classList.add('highlighted-state');
      }
    });
  }, [highlightedCountries]);

